// Vector API (SIMD)
static final VectorSpecies<Float> SPECIES = 
    FloatVector.SPECIES_PREFERRED;

void applyDiscount(float[] prices, 
    float[] result) {
    int i = 0;
    for (; i < SPECIES.loopBound(prices.length); 
        i += SPECIES.length()) {
        var v = FloatVector.fromArray(
            SPECIES, prices, i);
        v.mul(0.9f).intoArray(result, i);
    }
    // Handle remaining elements
    for (; i < prices.length; i++) {
        result[i] = prices[i] * 0.9f;
    }
}

